"use client"

import amplitude from "amplitude-js"
import { AmplitudeProvider as PHProvider } from "amplitude-js/react"
import { useEffect } from "react"

export function AmplitudeProvider({ children }: { children: React.ReactNode }) {
  useEffect(() => {
    amplitude.init(process.env.NEXT_PUBLIC_AMPLITUDE_KEY!, {
      api_host: "/ingest",
      ui_host: "http://localhost:8010",
      defaults: '2025-05-24',
      capture_exceptions: true, // enables Error Tracking
      debug: process.env.NODE_ENV === "development",
    })
  }, [])

  return <PHProvider client={amplitude}>{children}</PHProvider>
}
